   323→                                 int osr_bci,
   324→                                 int comp_level,
   325→                                 const methodHandle& hot_method,
   326→                                 int hot_count,
   327→                                 CompileTask::CompileReason compile_reason,
   328→                                 TRAPS);
   329→  static CompileQueue* c1_compile_queue();
   330→  static CompileQueue* c2_compile_queue();
