   332→private:
   333→  static nmethod* compile_method(const methodHandle& method,
   334→                                   int osr_bci,
   335→                                   int comp_level,
   336→                                   const methodHandle& hot_method,
   337→                                   int hot_count,
   338→                                   CompileTask::CompileReason compile_reason,
   339→                                   DirectiveSet* directive,
   340→                                   TRAPS);
